/* Reset — prevent browser default inconsistencies */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* Body — font, background, line height */
body {
  font-family: 'Inter', sans-serif;
  background-color: #f8f9fa;
  color: #1A2E5A;
  line-height: 1.6;
}

/* Navigation bar */
nav {
  background-color: #1A2E5A;
  padding: 1rem 2rem;
  display: flex;
  gap: 2rem;
}

/* Navigation links */
nav a {
  color: #ffffff;
  text-decoration: none;
  font-weight: 600;
  padding: 0.5rem 1rem;
  border-radius: 4px;
}

/* Hover state — pseudo-class */
nav a:hover {
  background-color: #F4B942;
  color: #1A2E5A;
}

/* Mobile first — base styles apply to all screens */
.card-grid {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  padding: 1rem;
}

.card {
  background: white;
  padding: 1.5rem;
  border-radius: 8px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  width: 100%; /* Full width on mobile */
}

/* Tablet — 768px and above */
@media (min-width: 768px) {
  .card-grid {
    flex-direction: row;
    flex-wrap: wrap;
  }
  .card {
    width: calc(50% - 0.5rem); /* Two columns */
  }
}

/* Desktop — 1024px and above */
@media (min-width: 1024px) {
  .card {
    width: calc(33.333% - 0.67rem); /* Three columns */
  }
}
